// ── GROWING WINDOW HELPER ──────────────────────────────────────
function buildGrowingWindow(startMonth, sem) {
  const harvestEnd = sem === 1 ? 3 : 9  // dry→Mar, wet→Sep
  const window = []
  let cur = startMonth
  for(let i = 0; i < 6; i++) {
    window.push(cur)
    if(cur === harvestEnd) break
    cur = cur === 12 ? 1 : cur + 1
  }
  return window
}

